(function(){const c=document.getElementById('bg-shapes');if(!c)return;['bg-shape bg-shape-1','bg-shape bg-shape-2','bg-shape bg-shape-3'].forEach(cls=>{const d=document.createElement('div');d.className=cls;c.appendChild(d)})})();

const STEPS=[
  {icon:'fa-user',title:'Identitas Pasien'},{icon:'fa-comment-medical',title:'Keluhan Utama'},
  {icon:'fa-file-medical',title:'Riwayat Penyakit'},{icon:'fa-people-group',title:'Riwayat Keluarga'},
  {icon:'fa-utensils',title:'Pola Aktivitas'},{icon:'fa-stethoscope',title:'Pemeriksaan Fisik'},
  {icon:'fa-flask',title:'Penunjang Lab / Ro'},{icon:'fa-robot',title:'AI Detector'},
  {icon:'fa-chart-bar',title:'Analisa Data'},{icon:'fa-hospital',title:'SDKI / SLKI / SIKI'},
  {icon:'fa-bolt',title:'Prioritas Masalah'},{icon:'fa-book',title:'Literatur & Referensi'}
];

let curStep=0,painVal=-1,labCount=0,roxCount=0,_diagResults=[];

(function(){const n=document.getElementById('navl');STEPS.forEach((s,i)=>{const d=document.createElement('div');d.className='nav-item'+(i===0?' active':'');d.innerHTML=`<i class="fas ${s.icon}"></i><span>${s.title}</span><span class="sn">${i+1}</span>`;d.onclick=()=>goStep(i);n.appendChild(d)})})();

function goStep(n){if(n<0||n>=STEPS.length)return;document.querySelectorAll('.step').forEach(el=>el.classList.remove('active'));curStep=n;const el=document.querySelector(`.step[data-s="${n}"]`);if(el)el.classList.add('active');document.querySelectorAll('.nav-item').forEach((ni,i)=>{ni.classList.toggle('active',i===n);if(i<n)ni.classList.add('done');else ni.classList.remove('done')});document.getElementById('stitle').textContent=`${n+1}. ${STEPS[n].title}`;const pct=Math.round((n/(STEPS.length-1))*100);document.getElementById('pfill').style.width=pct+'%';document.getElementById('ptext').textContent=pct+'%';window.scrollTo({top:0,behavior:'smooth'});document.getElementById('sidebar').classList.remove('open');document.getElementById('ovl').classList.remove('show');if(n===1&&document.getElementById('pain-scale')&&!document.getElementById('pain-scale').children.length)buildPain();if(n===5){calcGCS();calcIMT()}if(n===9)renderDiagnosis();if(n===10)renderPriority()}
function toggleSB(){document.getElementById('sidebar').classList.toggle('open');document.getElementById('ovl').classList.toggle('show')}
function toast(msg,type){type=type||'s';const icons={s:'fa-check-circle',e:'fa-times-circle',i:'fa-info-circle'};const t=document.createElement('div');t.className='toast t-'+type;t.innerHTML=`<i class="fas ${icons[type]}"></i>${msg}`;document.getElementById('toast-box').appendChild(t);setTimeout(()=>t.remove(),3200)}
function getVal(id){const el=document.getElementById(id);return el?el.value.trim():''}
function getChkVals(id){return[...document.querySelectorAll('#'+id+' .ci.ck')].map(el=>el.dataset.val)}
function chkClick(e){const ci=e.target.closest('.ci');if(!ci)return;ci.classList.toggle('ck');ci.querySelector('input').checked=ci.classList.contains('ck')}

// === CLEAR DATA ===
function clearAllData(){document.getElementById('clear-modal').style.display='flex'}
function closeClearModal(){document.getElementById('clear-modal').style.display='none'}
function confirmClear(){
  document.querySelectorAll('.fi, .fta').forEach(el=>{if(!el.readOnly)el.value=''});
  document.querySelectorAll('.fs').forEach(el=>el.selectedIndex=0);
  document.querySelectorAll('.ci.ck').forEach(el=>{el.classList.remove('ck');el.querySelector('input').checked=false});
  painVal=-1;
  document.querySelectorAll('.pb.sel').forEach(b=>{b.classList.remove('sel');b.style.background='';b.style.borderColor='';b.style.color=''});
  document.getElementById('lab-rows').innerHTML='';document.getElementById('rox-rows').innerHTML='';
  labCount=0;roxCount=0;addLabRow();addLabRow();addLabRow();addRoxRow();addRoxRow();
  ['analisa-subjektif','analisa-obyektif','analisa-masalah'].forEach(id=>document.getElementById(id).style.display='none');
  document.getElementById('data-s').innerHTML='';document.getElementById('data-o').innerHTML='';document.getElementById('data-masalah').innerHTML='';
  document.getElementById('dx-list').innerHTML='';document.getElementById('priority-list').innerHTML='';
  document.getElementById('ai-input').value='';document.getElementById('ai-result').innerHTML='';
  _diagResults=[];calcGCS();calcIMT();
  closeClearModal();toast('Semua data berhasil dihapus','s');
}

// === EXPORT MODAL ===
function openExportModal(){if(!_diagResults.length){toast('Jalankan analisis terlebih dahulu','e');return}document.getElementById('export-modal').style.display='flex'}
function closeExportModal(){document.getElementById('export-modal').style.display='none'}

// === PAIN ===
function buildPain(){const c=document.getElementById('pain-scale');if(!c)return;const colors=['#10b981','#34d399','#6ee7b7','#a3e635','#facc15','#f59e0b','#f97316','#ef4444','#dc2626','#b91c1c','#7f1d1d'];for(let i=0;i<=10;i++){const b=document.createElement('button');b.className='pb';b.textContent=i;b.onclick=()=>{painVal=i;document.querySelectorAll('.pb').forEach(x=>{x.classList.remove('sel');x.style.background='';x.style.borderColor='';x.style.color=''});b.classList.add('sel');b.style.background=colors[i];b.style.borderColor=colors[i];b.style.color='#fff'};c.appendChild(b)}}
function calcGCS(){const e=+getVal('f-gcs-e'),v=+getVal('f-gcs-v'),m=+getVal('f-gcs-m');document.getElementById('f-gcs-total').value=e+v+m;document.getElementById('f-gcs-total').style.color=(e+v+m)<=8?'var(--danger)':(e+v+m)<=12?'var(--warn)':'var(--accent)'}
function calcIMT(){const bb=+getVal('f-bb'),tb=+getVal('f-tb')/100;if(bb>0&&tb>0){const imt=(bb/(tb*tb)).toFixed(1);document.getElementById('f-imt').value=imt;document.getElementById('f-imtkat').value=imt<18.5?'Kurus':imt<25?'Normal':imt<30?'Gemuk':'Obesitas'}else{document.getElementById('f-imt').value='';document.getElementById('f-imtkat').value=''}}
function addLabRow(){labCount++;const d=document.createElement('div');d.className='g3 lab-row';d.innerHTML=`<div class="fg"><input class="fi lab-p" placeholder="Parameter"></div><div class="fg"><input class="fi lab-v" placeholder="Nilai"></div><div class="fg"><input class="fi lab-n" placeholder="Normal"></div>`;document.getElementById('lab-rows').appendChild(d)}
function addRoxRow(){roxCount++;const d=document.createElement('div');d.className='g2 rox-row';d.innerHTML=`<div class="fg"><input class="fi rox-t" placeholder="Jenis pemeriksaan"></div><div class="fg"><input class="fi rox-r" placeholder="Hasil"></div>`;document.getElementById('rox-rows').appendChild(d)}
function getLabData(){const r=[];document.querySelectorAll('#lab-rows .lab-row').forEach(d=>{const p=d.querySelector('.lab-p').value.trim(),v=d.querySelector('.lab-v').value.trim(),n=d.querySelector('.lab-n').value.trim();if(p||v)r.push({p,v,n})});return r}
function getRoxData(){const r=[];document.querySelectorAll('#rox-rows .rox-row').forEach(d=>{const t=d.querySelector('.rox-t').value.trim(),res=d.querySelector('.rox-r').value.trim();if(t||res)r.push({t,res})});return r}

