{id:'00126',lb:'Kurang Pengetahuan',dom:'Kesehatan',def:'Ketiadaan/kurangnya informasi kognitif terkait topik tertentu.',kw:['tidak tahu','kurang paham','belum paham','salah paham','butuh edukasi','perlu informasi','belum tahu','bertanya','pengetahuan kurang','tidak mengerti'],bp:4,slki:[{lb:'Pengetahuan: Proses Penyakit',ind:['Menjelaskan proses penyakit','Menjelaskan tanda-tanda','Menjelaskan faktor risiko']},{lb:'Pengetahuan: Prosedur',ind:['Menjelaskan tujuan tindakan','Menjelaskan prosedur','Menyebutkan efek samping']}],siki:[{lb:'Pengajaran: Proses Penyakit',act:['Assess tingkat pengetahuan','Identifikasi kebutuhan belajar','Gunakan metode pengajaran sesuai','Berikan informasi penyakit','Gunakan media: leaflet,video,gambar','Ajarkan tanda bahaya','Libatkan keluarga','Evaluasi dengan teach-back','Dokumentasikan materi','Berikan lembar edukasi']}]}
