  C.innerHTML+=`<div class="step" data-s="2"><div class="card"><div class="ct"><i class="fas fa-file-medical"></i> Riwayat Penyakit Sekarang</div>${ft('f-riwayatsekarang','Anamnesis',4)}</div><div class="card"><div class="ct"><i class="fas fa-clipboard-list"></i> Riwayat Penyakit Dahulu</div><div class="fg"><label class="fl">Penyakit yang pernah diderita</label><div class="cgrp" id="chk-riwayatdahulu" onclick="chkClick(event)">${ck('DM')+ck('Hipertensi')+ck('Jantung')+ck('Asma')+ck('TB Paru')+ck('Ginjal')+ck('Stroke')+ck('Kanker')}</div></div><div class="g2">${ft('f-riwayatop','Riwayat Operasi',2)+ft('f-alergi','Riwayat Alergi',2)}</div></div>${nav(1,3)}</div>`;
