  C.innerHTML+=`<div class="step" data-s="4"><div class="card"><div class="ct"><i class="fas fa-utensils"></i> Pola Nutrisi</div><p style="font-size:11px;color:var(--muted);margin-bottom:8px;font-weight:600">Sebelum sakit</p><div class="g3">${f('f-nafsubefore','Nafsu Makan','sel',['','— Pilih —','Baik','Cukup','Kurang'])+f('f-jmlmakanbefore','Jumlah/Hari','text')+f('f-jnsmakanbefore','Jenis','text')}</div><p style="font-size:11px;color:var(--muted);margin:10px 0;font-weight:600">Saat sakit</p><div class="g3">${f('f-nafsuafter','Nafsu Makan','sel',['','— Pilih —','Baik','Cukup','Kurang','Tidak ada'])+f('f-jmlmakanafter','Jumlah/Hari','text')+f('f-ubahbb','Perubahan BB','sel',['','— Pilih —','Turun >10%','Turun 5-10%','Turun <5%','Tetap','Naik'])}</div><div class="fg"><label class="fl">Kesulitan Makan</label><div class="cgrp" id="chk-kesulitanmakan" onclick="chkClick(event)">${ck('Mual')+ck('Muntah')+ck('Dysphagia')+ck('Diet khusus')+ck('NGT')}</div></div></div><div class="card"><div class="ct"><i class="fas fa-glass-water"></i> Pola Cairan</div><div class="g3">${f('f-jenisminum','Jenis','text')+f('f-jmlminum','Jumlah/hari','text')+f('f-ivfd','IVFD','text')}</div></div><div class="card"><div class="ct"><i class="fas fa-toilet"></i> Pola Eliminasi</div><div class="g2"><div><p style="font-size:12px;font-weight:700;color:var(--text2);margin-bottom:6px">BAK</p><div class="g2">${f('f-bakfreq','Frekuensi','text')+f('f-bakwarna','Warna','sel',['','— Pilih —','Kuning jerami','Kuning pekat','Cokelat','Merah'])}</div><div class="fg"><label class="fl">Kelainan BAK</label><div class="cgrp" id="chk-bak" onclick="chkClick(event)">${ck('Anyang-anyangan')+ck('Hematuria')+ck('Kateter')+ck('Inkontinensia')+ck('Retensi')}</div></div></div><div><p style="font-size:12px;font-weight:700;color:var(--text2);margin-bottom:6px">BAB</p><div class="g2">${f('f-babfreq','Frekuensi','text')+f('f-babkons','Konsistensi','sel',['','— Pilih —','Lunak','Padat','Cair','Berak hitam','Konstipasi'])}</div><div class="fg"><label class="fl">Kelainan BAB</label><div class="cgrp" id="chk-bab" onclick="chkClick(event)">${ck('Diare')+ck('Konstipasi')+ck('Melena')+ck('Darah')}</div></div></div></div></div><div class="card"><div class="ct"><i class="fas fa-bed"></i> Pola Tidur & Aktivitas</div><div class="g2">${f('f-tidurdurasi','Durasi Tidur','text')+f('f-tidurkualitas','Kualitas','sel',['','— Pilih —','Baik','Cukup','Kurang','Sangat Kurang'])}</div><div class="g2"><div class="fg"><label class="fl">Gangguan Tidur</label><div class="cgrp" id="chk-ganggtidur" onclick="chkClick(event)">${ck('Insomnia')+ck('Terbangun')+ck('Mimpi buruk')}</div></div><div class="fg">${f('f-mobilisasi','Mobilisasi','sel',['','— Pilih —','Bedrest total','Tirah baring','Duduk di kursi','Jalan dengan bantuan','Jalan mandiri','Mobile penuh'])}</div></div><div class="fg"><label class="fl">Hygiene</label><div class="cgrp" id="chk-hygiene" onclick="chkClick(event)">${ck('Mandi sendiri')+ck('Mandi dibantu')+ck('Gosok gigi sendiri')+ck('Dibantu perawat')}</div></div></div>${nav(3,5)}</div>`;
