  C.innerHTML+=`<div class="step" data-s="6"><div class="card"><div class="ct"><i class="fas fa-flask"></i> Laboratorium</div><div id="lab-rows"></div><button class="btn btn-sm btn-s" style="margin-top:8px" onclick="addLabRow()"><i class="fas fa-plus"></i> Tambah Parameter</button></div><div class="card"><div class="ct"><i class="fas fa-x-ray"></i> Radiologi</div><div id="rox-rows"></div><button class="btn btn-sm btn-s" style="margin-top:8px" onclick="addRoxRow()"><i class="fas fa-plus"></i> Tambah Pemeriksaan</button></div><div class="card"><div class="ct"><i class="fas fa-wave-square"></i> Pemeriksaan Lainnya</div>${ft('f-ekg','EKG',2)+ft('f-lainpenunjang','USG / CT Scan / MRI',2)}</div>${nav(5,7)}</div>`;
  C.innerHTML+=`<div class="step" data-s="7"><div class="card card-glow"><div class="ct"><i class="fas fa-robot"></i> AI Smart Detector <span class="badge b-a" style="margin-left:6px"><span class="pulse-dot"></span> INTELLIGENT</span></div><p style="font-size:12px;color:var(--text2);margin-bottom:14px">Tempelkan salinan catatan medis. AI mendeteksi SDKI, SLKI, SIKI secara otomatis.</p><div class="aiz"><textarea id="ai-input" placeholder="Tempelkan teks catatan medis...&#10;&#10;Contoh: Pasien nyeri dada 3 jam, NRS 7/10. TD 150/90, N 102, RR 28, SPO2 89%. Sesak, sianosis. Terpasang kateter. Lab: Hb 8.2, Leukosit 15000, Trombosit 80000. Ro: kardiomegali, edema paru. Cemas, sulit tidur. Riwayat DM dan hipertensi. Nafsu makan berkurang."></textarea></div><div style="display:flex;gap:8px;margin-top:12px" class="no-print"><button class="btn btn-p" onclick="runAI()"><i class="fas fa-wand-magic-sparkles"></i> Analisis dengan AI</button><button class="btn btn-s" onclick="document.getElementById('ai-input').value='';document.getElementById('ai-result').innerHTML=''"><i class="fas fa-eraser"></i> Bersihkan</button></div><div id="ai-result"></div></div>${nav(6,8)}</div>`;
