  C.innerHTML+=`<div class="step" data-s="9"><div class="card"><div class="ct"><i class="fas fa-hospital"></i> Diagnosis Keperawatan — SDKI, SLKI, SIKI</div><p style="font-size:12px;color:var(--text2);margin-bottom:12px">Klik kartu untuk detail. Tombol export tersedia di halaman Analisa Data.</p><div style="display:flex;gap:8px;flex-wrap:wrap" class="no-print"><button class="btn btn-p" onclick="goStep(8);runAnalysis();setTimeout(function(){renderDiagnosis();goStep(9)},400)"><i class="fas fa-rotate"></i> Refresh</button><button class="btn" style="background:var(--purple);color:#fff" onclick="openExportModal()"><i class="fas fa-file-export"></i> Export PDF / DOC</button></div></div><div id="dx-list"></div>${nav(8,10)}</div>`;
  C.innerHTML+=`<div class="step" data-s="10"><div class="card"><div class="ct"><i class="fas fa-bolt"></i> Prioritas Masalah Keperawatan</div><div style="display:flex;gap:10px;margin-bottom:14px;flex-wrap:wrap"><div style="display:flex;align-items:center;gap:5px;font-size:11px"><span style="width:10px;height:10px;border-radius:2px;background:#dc2626;display:inline-block"></span>P1 — Mengancam Jiwa</div><div style="display:flex;align-items:center;gap:5px;font-size:11px"><span style="width:10px;height:10px;border-radius:2px;background:#d97706;display:inline-block"></span>P2 — Bahaya/Keamanan</div><div style="display:flex;align-items:center;gap:5px;font-size:11px"><span style="width:10px;height:10px;border-radius:2px;background:#0d9488;display:inline-block"></span>P3 — Kenyamanan</div><div style="display:flex;align-items:center;gap:5px;font-size:11px"><span style="width:10px;height:10px;border-radius:2px;background:#7c3aed;display:inline-block"></span>P4 — Psikologis</div></div><div style="display:flex;gap:8px;flex-wrap:wrap" class="no-print"><button class="btn btn-p" onclick="goStep(8);runAnalysis();setTimeout(function(){renderPriority();goStep(10)},400)"><i class="fas fa-rotate"></i> Refresh</button><button class="btn" style="background:var(--purple);color:#fff" onclick="openExportModal()"><i class="fas fa-file-export"></i> Export PDF / DOC</button><button class="btn btn-s" onclick="printRes()"><i class="fas fa-print"></i> Cetak</button></div></div><div id="priority-list"></div><div class="snav"><button class="btn btn-s" onclick="goStep(9)"><i class="fas fa-arrow-left"></i> Sebelumnya</button></div></div>`;
